"use strict";(self.webpackChunkdocusaurus=self.webpackChunkdocusaurus||[]).push([[849],{6164:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"explorerSidebar":[{"type":"link","label":"Explorer Guide","href":"/docs/explorer/intro","docId":"explorer/intro","unlisted":false},{"type":"category","label":"Explorer Documentation","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Explorer Full Documentation","href":"/docs/explorer/full-docs/intro","docId":"explorer/full-docs/intro","unlisted":false}],"href":"/docs/explorer/full-docs"}],"musicEditorSidebar":[{"type":"link","label":"Music Editor Guide","href":"/docs/music-editor/intro","docId":"music-editor/intro","unlisted":false},{"type":"category","label":"Music Editor Documentation","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Music Editor Full Documentation","href":"/docs/music-editor/full-docs/intro","docId":"music-editor/full-docs/intro","unlisted":false},{"type":"link","label":"Beat Grid","href":"/docs/music-editor/full-docs/beat-grid","docId":"music-editor/full-docs/beat-grid","unlisted":false},{"type":"link","label":"Tempo Editor","href":"/docs/music-editor/full-docs/tempo-editor","docId":"music-editor/full-docs/tempo-editor","unlisted":false},{"type":"link","label":"Lyrics Editor","href":"/docs/music-editor/full-docs/lyrics-editor","docId":"music-editor/full-docs/lyrics-editor","unlisted":false}],"href":"/docs/music-editor/full-docs"}],"developerSidebar":[{"type":"link","label":"Developer Guide","href":"/docs/developer/intro","docId":"developer/intro","unlisted":false},{"type":"category","label":"Developer Documentation","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"An\u0131\u20f0mr Full Developer Documentation","href":"/docs/developer/full-docs/intro","docId":"developer/full-docs/intro","unlisted":false},{"type":"link","label":"Getting Started with An\u0131\u20f0mr Development","href":"/docs/developer/full-docs/getting-started","docId":"developer/full-docs/getting-started","unlisted":false},{"type":"link","label":"Event-Based System","href":"/docs/developer/full-docs/event-based-system","docId":"developer/full-docs/event-based-system","unlisted":false},{"type":"link","label":"Module Collections","href":"/docs/developer/full-docs/module-collection","docId":"developer/full-docs/module-collection","unlisted":false},{"type":"link","label":"Animation Configuration","href":"/docs/developer/full-docs/animation-config","docId":"developer/full-docs/animation-config","unlisted":false},{"type":"link","label":"G Object Reference","href":"/docs/developer/full-docs/g-object-reference","docId":"developer/full-docs/g-object-reference","unlisted":false}],"href":"/docs/developer/full-docs"}],"tutorialSidebar":[]},"docs":{"about":{"id":"about","title":"About An\u0131\u20f0mr","description":"An\u0131\u20f0mr is a platform where music meets animation. Users can experience synchronized animations with songs or get creative by contributing song data or coding custom animations. Whether you\'re a music lover or a developer, An\u0131\u20f0mr lets you watch, play, and contribute to interactive music experiences."},"developer/full-docs/animation-config":{"id":"developer/full-docs/animation-config","title":"Animation Configuration","description":"Animations can expose configurable parameters that users adjust without touching the code. You define these parameters in the animation\'s config array, and the platform renders the appropriate input controls automatically.","sidebar":"developerSidebar"},"developer/full-docs/event-based-system":{"id":"developer/full-docs/event-based-system","title":"Event-Based System","description":"In An\u0131\u20f0mr, the Event-Based System allows your modules to react to various built-in and custom events. This functionality enables dynamic interactions within your animations and games, enhancing user experience and engagement.","sidebar":"developerSidebar"},"developer/full-docs/g-object-reference":{"id":"developer/full-docs/g-object-reference","title":"G Object Reference","description":"The G object is passed as the first argument to your module\'s default export function. It is your module\'s interface to the platform \u2014 for event handling, DOM access, config values, and communication with other modules.","sidebar":"developerSidebar"},"developer/full-docs/getting-started":{"id":"developer/full-docs/getting-started","title":"Getting Started with An\u0131\u20f0mr Development","description":"Welcome to the development section of An\u0131\u20f0mr! In this guide, you\'ll learn how to create animations and games that sync with music using the An\u0131\u20f0mr platform. Development is entirely browser-based, so you won\u2019t need to set up a local environment. Here\'s how you can get started:","sidebar":"developerSidebar"},"developer/full-docs/intro":{"id":"developer/full-docs/intro","title":"An\u0131\u20f0mr Full Developer Documentation","description":"Welcome to the An\u0131\u20f0mr Full Developer Documentation! This guide is designed to help developers create dynamic animations and games that are synchronized with music, all within a browser-based environment. Whether you\'re creating simple visual effects or complex interactive games, this documentation will walk you through the core concepts and advanced techniques for building on the An\u0131\u20f0mr platform.","sidebar":"developerSidebar"},"developer/full-docs/module-collection":{"id":"developer/full-docs/module-collection","title":"Module Collections","description":"In An\u0131\u20f0mr, a module collection is a grouping of one or more modules or even other module collections. It serves to organize and define the layout of these modules while also managing event routing within the collection.","sidebar":"developerSidebar"},"developer/intro":{"id":"developer/intro","title":"Developer Guide","description":"Welcome, Developers! This guide will help you dive into the technical side of An\u0131\u20f0mr by contributing code for animations, games, and more.","sidebar":"developerSidebar"},"explorer/full-docs/intro":{"id":"explorer/full-docs/intro","title":"Explorer Full Documentation","description":"Welcome to the complete guide for exploring An\u0131\u20f0mr. This page covers every control and setting available in the player.","sidebar":"explorerSidebar"},"explorer/intro":{"id":"explorer/intro","title":"Explorer Guide","description":"Welcome, Explorers! This guide is designed to help you get the most out of An\u0131\u20f0mr by watching animations and playing games synced to music.","sidebar":"explorerSidebar"},"music-editor/full-docs/beat-grid":{"id":"music-editor/full-docs/beat-grid","title":"Beat Grid","description":"The beat grid is the main timing editor. It displays the song\'s timeline as a grid of beats and measures, and lets you place, move, and delete timing events.","sidebar":"musicEditorSidebar"},"music-editor/full-docs/intro":{"id":"music-editor/full-docs/intro","title":"Music Editor Full Documentation","description":"The music editor is where song data is created and refined. Accurate data is what lets animations sync precisely to the music \u2014 every beat marker, lyric line, and chord you add improves the experience for every animation that uses that song.","sidebar":"musicEditorSidebar"},"music-editor/full-docs/lyrics-editor":{"id":"music-editor/full-docs/lyrics-editor","title":"Lyrics Editor","description":"The lyrics editor lets you add, import, and time-align lyrics. Accurate lyric timing enables animations to react to individual lines, words, and syllables in sync with the music.","sidebar":"musicEditorSidebar"},"music-editor/full-docs/tempo-editor":{"id":"music-editor/full-docs/tempo-editor","title":"Tempo Editor","description":"The tempo editor lets you set and refine the BPM (beats per minute) of a song. Getting BPM right is the most important step \u2014 all beat-relative events (beats, measures, chords, sections, lyrics) are positioned using beat numbers, and their playback times are derived from the BPM. An accurate BPM means accurate sync.","sidebar":"musicEditorSidebar"},"music-editor/intro":{"id":"music-editor/intro","title":"Music Editor Guide","description":"Welcome, Music Editors! In this guide, you\'ll learn how to contribute song data and ensure that the music syncs perfectly with animations and games.","sidebar":"musicEditorSidebar"}}}}')}}]);